import React from 'react';
import { ErrorMessage, useField, Field, useFormikContext } from 'formik';
import { useTranslation } from 'react-i18next';
import "./KarimField.scss";
import { FaExclamationCircle } from 'react-icons/fa';

type KarimFieldProps = {
  name: string;
  type: string;
  className?: string;
};

const KarimField: React.FC<KarimFieldProps> = ({ name, type, className = "", ...props }) => {
  const { t } = useTranslation();
  const [field, meta] = useField({ name, ...props });
  const formik = useFormikContext<any>();

  const isError = meta.touched && meta.error;
  const hasValue = !!field.value; 
  const inputClass = isError ? `${className} is-invalid` : hasValue ? `${className}hasValue` : `${className} `;

  if( type === "checkbox"){
    return (
      <div className="KarimCheckbox">

<label className="cont">
  <input  
  checked={formik.values[name] === 1}
    type="checkbox" 
    name={name}
    onChange={() =>
      formik.setFieldValue(name, formik.values[name] === 1 ? 0 : 1)} />
  <span/>
  {name}
</label>

</div>



    )
  }else if( type === "select"){
      return(
        <div className="select-box">
  <div className="select-box__current" tabIndex={1}>
    <div className="select-box__value">
      <input
        className="select-box__input"
        type="radio"
        id={0}
        defaultValue={1}
        name="Ben"
        defaultChecked="checked"
      />
      <p className="select-box__input-text">Cream</p>
    </div>
    <div className="select-box__value">
      <input
        className="select-box__input"
        type="radio"
        id={1}
        defaultValue={2}
        name="Ben"
      />
      <p className="select-box__input-text">Cheese</p>
    </div>
    <div className="select-box__value">
      <input
        className="select-box__input"
        type="radio"
        id={2}
        defaultValue={3}
        name="Ben"
      />
      <p className="select-box__input-text">Milk</p>
    </div>
    <div className="select-box__value">
      <input
        className="select-box__input"
        type="radio"
        id={3}
        defaultValue={4}
        name="Ben"
      />
      <p className="select-box__input-text">Honey</p>
    </div>
    <div className="select-box__value">
      <input
        className="select-box__input"
        type="radio"
        id={4}
        defaultValue={5}
        name="Ben"
      />
      <p className="select-box__input-text">Toast</p>
    </div>
    <img
      className="select-box__icon"
      src="http://cdn.onlinewebfonts.com/svg/img_295694.svg"
      alt="Arrow Icon"
      aria-hidden="true"
    />
  </div>
  <ul className="select-box__list">
    <li>
      <label
        className="select-box__option"
        htmlFor={0}
        aria-hidden="aria-hidden"
      >
        Cream
      </label>
    </li>
    <li>
      <label
        className="select-box__option"
        htmlFor={1}
        aria-hidden="aria-hidden"
      >
        Cheese
      </label>
    </li>
    <li>
      <label
        className="select-box__option"
        htmlFor={2}
        aria-hidden="aria-hidden"
      >
        Milk
      </label>
    </li>
    <li>
      <label
        className="select-box__option"
        htmlFor={3}
        aria-hidden="aria-hidden"
      >
        Honey
      </label>
    </li>
    <li>
      <label
        className="select-box__option"
        htmlFor={4}
        aria-hidden="aria-hidden"
      >
        Toast
      </label>
    </li>
  </ul>
</div>

      )
  } 
  else {
    return (
    <div className="KarimField">
      <label htmlFor={field.name} className="text">
      {isError ?  <span className='isErrorIcon'> <FaExclamationCircle/></span> :""}  {name} {""} 
        <ErrorMessage name={field.name}>
        {(msg: any) => <span className="field-error text-danger isErrorIcon">{t(msg)} <FaExclamationCircle/> </span>}
      </ErrorMessage>
      </label>

      <Field
        type={type}
        placeholder="Write Here..."
        name={field.name}
        className={inputClass}
      />


    </div>



  );
  }
};

export default KarimField;
